1	import { _decorator, Component, Node, Label, tween, v3, warn, error, EventKeyboard, Input, input, KeyCode, log } from 'cc';
2	import { DEV, DEBUG } from 'cc/env';
3	import GameView from '../GameView';
4	import { eventManager } from 'db://astarte-framework/Managers';
5	import { SpriteChange } from '../Common/SpriteChange';
6	import {
7	    SegmentDescriptor,
8	    SpinResult,
9	    FeatureWheelSegmentType,
10	    FEATURE_WHEEL_SEGMENT_COUNT,
11	    DEFAULT_ICON_INDEX,
12	    TypeToIconIndex,
13	    ComputeTargetAngle,
14	    NormalizeAngle,
15	    GetDefaultSegments,
16	} from './FeatureWheelTypes';
17	
18	const { ccclass, property } = _decorator;
19	
20	/**
21	 * @ch Feature Wheel 事件（獨立命名空間，與舊 MULTIPLIER_EVENT 不衝突，支援共存）
22	 */
23	export const FEATURE_WHEEL_EVENT = {
24	    /**
25	     * @ch 初始化
26	     * @param gameView 遊戲視窗
27	     */
28	    INIT: 'FEATURE_WHEEL_INIT',
29	
30	    /**
31	     * @ch 設置 12 格輪盤資料（server 給）
32	     * @param segments SegmentDescriptor[]（每格 type + 選填 value）
33	     */
34	    SET_WHEEL_DATA: 'FEATURE_WHEEL_SET_WHEEL_DATA',
35	
36	    /**
37	     * @ch 轉動並落在指定格
38	     * @param landIndex 落點格索引 (0~11)
39	     * @param callback (選填) (result: SpinResult) => void
40	     */
41	    PLAY_SPIN: 'FEATURE_WHEEL_PLAY_SPIN',
42	
43	    /**@ch 顯示 UI*/
44	    SHOW_UI: 'FEATURE_WHEEL_SHOW_UI',
45	
46	    /**@ch 隱藏 UI*/
47	    HIDE_UI: 'FEATURE_WHEEL_HIDE_UI',
48	
49	    /**
50	     * @ch 手動恢復 Idle 緩轉
51	     * PlaySpin 後輪盤停住不自動恢復；待盤面其他表演結束，由呼叫端 dispatch 此事件才繼續緩轉
52	     */
53	    RESUME_IDLE: 'FEATURE_WHEEL_RESUME_IDLE',
54	};
55	
56	/**
57	 * @ch Feature Wheel 輪盤 UI 元件
58	 * 單一職責：顯示 12 格、平時 Idle 緩轉、依 server 資料換 icon、轉動落在指定格、播落點演出、把選中功能拋給外部
59	 * 不碰盤面標記/重轉/改符號（呼叫端責任）
60	 */
61	@ccclass('FeatureWheelManager')
62	export class FeatureWheelManager extends Component {
63	    //#region 屬性
64	    /**@ch 根節點（顯示/隱藏）*/
65	    @property({ type: Node, displayName: '根節點' })
66	    private m_rootNode: Node = null;
67	
68	    /**@ch 輪盤旋轉節點（轉動的是這個，頂端指針固定不動）*/
69	    @property({ type: Node, displayName: '輪盤旋轉節點' })
70	    private m_wheelNode: Node = null;
71	
72	    /**@ch 魔法字環節點*/
73	    @property({ type: Node, displayName: '魔法字環節點' })
74	    private m_magicWordRingNode: Node = null;
75	
76	    /**@ch 12 格 icon 的 SpriteChange（順序對應格 0~11）*/
77	    @property({ type: [SpriteChange], displayName: '12 格 icon SpriteChange' })
78	    private m_segmentSpriteChanges: SpriteChange[] = [];
79	
80	    /**@ch 12 格乘倍數值 Label（非乘倍格留空字串；順序對應格 0~11）*/
81	    @property({ type: [Label], displayName: '12 格乘倍數值 Label' })
82	    private m_segmentValueLabels: Label[] = [];
83	
84	    /**@ch 12 格落點演出節點（高亮+scale 的目標；順序對應格 0~11）*/
85	    @property({ type: [Node], displayName: '12 格落點演出節點' })
86	    private m_segmentNodes: Node[] = [];
87	
88	    /**@ch 轉動方向：勾選=順時針，取消=逆時針（預設順時針）*/
89	    @property({ displayName: '順時針轉動' })
90	    private m_clockwise: boolean = true;
91	
92	    /**@ch Idle 緩轉一圈秒數（越大越慢；≤0 視為不緩轉）；方向跟隨「順時針轉動」*/
93	    @property({ displayName: 'Idle 一圈秒數' })
94	    private m_idleSecondsPerRev: number = 60;
95	    //#endregion 屬性
96	
97	    //#region 常數
98	    /**@ch 轉動時間（秒）；拉長以降低峰值角速度，減輕 12 格重複圖樣的車輪錯覺（視覺反向）*/
99	    private static readonly ROTATE_TIME = 2.5;
100	    /**@ch 落點演出放大倍率*/
101	    private static readonly ANNOUNCE_SCALE = 1.25;
102	    /**@ch 落點演出單段時間（秒）*/
103	    private static readonly ANNOUNCE_TIME = 0.18;
104	    //#endregion 常數
105	
106	    //#region 變數
107	    /**@ch 遊戲視窗*/
108	    private m_gameView: GameView = null;
109	    /**@ch 是否初始化*/
110	    private m_isInit = false;
111	    /**@ch 是否轉動中（轉動中/閒置兩互斥態）*/
112	    private m_isSpinning = false;
113	    /**@ch 是否處於 Idle 緩轉態（SHOW_UI/RESUME_IDLE 開、HIDE_UI/PlaySpin 關；轉動中由 m_isSpinning 暫停，轉完不自動恢復）*/
114	    private m_isIdle = false;
115	    /**@ch 是否已註冊事件*/
116	    private m_isEventRegistered = false;
117	    /**@ch 當前 12 格資料*/
118	    private m_segments: SegmentDescriptor[] = [];
119	
120	    /**@ch 事件列表*/
121	    private readonly EVENT_LIST: string[] = [
122	        FEATURE_WHEEL_EVENT.INIT,
123	        FEATURE_WHEEL_EVENT.SET_WHEEL_DATA,
124	        FEATURE_WHEEL_EVENT.PLAY_SPIN,
125	        FEATURE_WHEEL_EVENT.SHOW_UI,
126	        FEATURE_WHEEL_EVENT.HIDE_UI,
127	        FEATURE_WHEEL_EVENT.RESUME_IDLE,
128	    ];
129	    //#endregion 變數
130	
131	    //#region 生命週期
132	    onLoad() {
133	        this.RegisterEvent();
134	        this.DevAssertConfig();
135	        this.RegisterTestKeyCodes();
136	    }
137	
138	    onDestroy() {
139	        this.UnregisterEvent();
140	        this.UnregisterTestKeyCodes();
141	    }
142	
143	    /**
144	     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
145	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
146	     */
147	    update(dt: number) {
148	        if (!this.m_isIdle || this.m_isSpinning) {
149	            return;
150	        }
151	        if (this.m_idleSecondsPerRev <= 0) {
152	            return;
153	        }
154	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
155	            return;
156	        }
157	        const dir = this.m_clockwise ? -1 : 1;
158	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
159	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
160	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
161	        this.m_wheelNode.setRotationFromEuler(0, 0, next);
162	    }
163	    //#endregion 生命週期
164	
165	    //#region 事件註冊
166	    private RegisterEvent() {
167	        if (this.m_isEventRegistered) {
168	            return;
169	        }
170	        this.m_isEventRegistered = true;
171	        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
172	    }
173	
174	    private UnregisterEvent() {
175	        if (!this.m_isEventRegistered) {
176	            return;
177	        }
178	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
179	        this.m_isEventRegistered = false;
180	    }
181	
182	    /**
183	     * @ch 事件分派
184	     */
185	    OnEvent(event: string, ...args: any[]) {
186	        switch (event) {
187	            case FEATURE_WHEEL_EVENT.INIT:
188	                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
189	                    this.Init(args[0]);
190	                } else {
191	                    error('FeatureWheel INIT 參數無效');
192	                }
193	                break;
194	
195	            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
196	                if (args.length > 0 && Array.isArray(args[0])) {
197	                    this.SetWheelData(args[0]);
198	                } else {
199	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
200	                }
201	                break;
202	
203	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
204	                if (args.length > 0 && typeof args[0] === 'number') {
205	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
206	                } else {
207	                    error('FeatureWheel PLAY_SPIN 參數無效');
208	                }
209	                break;
210	
211	            case FEATURE_WHEEL_EVENT.SHOW_UI:
212	                this.SetUIShow(true);
213	                break;
214	
215	            case FEATURE_WHEEL_EVENT.HIDE_UI:
216	                this.SetUIShow(false);
217	                break;
218	
219	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
220	                this.ResumeIdle();
221	                break;
222	        }
223	    }
224	    //#endregion 事件註冊
225	
226	    //#region 方法
227	    /**
228	     * @ch 初始化（IF-1）
229	     */
230	    private Init(gameView: GameView) {
231	        this.m_gameView = gameView;
232	        this.m_isInit = true;
233	    }
234	
235	    /**
236	     * @ch 設置 12 格資料並更新 icon（IF-2 / BC-5 / EH-2）
237	     * @param segments server 給的 12 格資料
238	     */
239	    private SetWheelData(segments: SegmentDescriptor[]) {
240	        // BC-9 行為約束：轉動中拒絕換資料，避免落點與顯示不一致
241	        if (this.m_isSpinning) {
242	            warn('FeatureWheel SetWheelData 轉動中，拒絕本次設置');
243	            return;
244	        }
245	        if (!segments) {
246	            warn('FeatureWheel SetWheelData 資料為空');
247	            return;
248	        }
249	
250	        // EH-2：長度 > 10 取前 10
251	        if (segments.length > FEATURE_WHEEL_SEGMENT_COUNT) {
252	            warn(`FeatureWheel SetWheelData 長度 ${segments.length} > ${FEATURE_WHEEL_SEGMENT_COUNT}，取前 ${FEATURE_WHEEL_SEGMENT_COUNT} 格`);
253	        }
254	        this.m_segments = segments.slice(0, FEATURE_WHEEL_SEGMENT_COUNT);
255	
256	        // EH-2：長度 < 10 → 渲染已提供格，其餘格保持預設
257	        if (this.m_segments.length < FEATURE_WHEEL_SEGMENT_COUNT) {
258	            warn(`FeatureWheel SetWheelData 長度 ${this.m_segments.length} < ${FEATURE_WHEEL_SEGMENT_COUNT}，其餘格保持預設`);
259	        }
260	
261	        this.BindSegmentIcons();
262	    }
263	
264	    /**
265	     * @ch 依當前資料綁定各格 icon 與乘倍數值（BC-5 / BC-4 / EH-2 未知 type）
266	     */
267	    private BindSegmentIcons() {
268	        // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
269	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
270	            const seg = i < this.m_segments.length ? this.m_segments[i] : null;
271	
272	            // 換 icon（BC-4：未知 type 由 TypeToIconIndex 回傳預設索引；無資料格用預設）
273	            const spriteChange = this.m_segmentSpriteChanges[i];
274	            if (spriteChange) {
275	                spriteChange.ChangeSpriteByIndex(seg ? TypeToIconIndex(seg.type) : DEFAULT_ICON_INDEX);
276	            }
277	
278	            // 乘倍數值（BC-5：僅乘倍格顯示 x{value}；其餘格空字串）
279	            const label = this.m_segmentValueLabels[i];
280	            if (label) {
281	                label.string = (seg && seg.type === FeatureWheelSegmentType.Multiplier && seg.value !== undefined)
282	                    ? `x${seg.value}`
283	                    : '';
284	            }
285	        }
286	    }
287	
288	    /**
289	     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
290	     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
291	     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
292	     * @param landIndex 落點格索引 (0~11)
293	     * @param callback 完成回調，帶選中格 {index, type, value}
294	     */
295	    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
296	        // ① BC-9 轉動中重入 → 忽略
297	        if (this.m_isSpinning) {
298	            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
299	            return;
300	        }
301	        // ② EH-3 未初始化或無資料
302	        if (!this.m_isInit || this.m_segments.length === 0) {
303	            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
304	            return;
305	        }
306	        // ③ EH-1 landIndex 範圍
307	        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
308	            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
309	            return;
310	        }
311	
312	        this.m_isSpinning = true;
313	        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
314	        this.m_isIdle = false;
315	        try {
316	            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
317	            await this.PlayLandAnnounce(landIndex);  // BC-7
318	            const seg = this.m_segments[landIndex];
319	            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
320	            try {
321	                callback?.({ index: landIndex, type: seg.type, value: seg.value });
322	            } catch (cbErr) {
323	                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
324	            }
325	        } catch (e) {
326	            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
327	        } finally {
328	            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
329	            this.m_isSpinning = false;
330	        }
331	    }
332	
333	    /**
334	     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
335	     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
336	     */
337	    private RotateToIndex(landIndex: number): Promise<void> {
338	        return new Promise<void>((resolve) => {
339	            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
340	                resolve();
341	                return;
342	            }
343	            const currentAngle = this.m_wheelNode.eulerAngles.z;
344	            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
345	            const anim = { angle: currentAngle };
346	            tween(anim)
347	                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
348	                    easing: 'cubicOut',
349	                    onUpdate: () => {
350	                        if (this.m_wheelNode?.isValid) {
351	                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
352	                        }
353	                    },
354	                })
355	                .call(() => {
356	                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
357	                    if (this.m_wheelNode?.isValid) {
358	                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
359	                    }
360	                    resolve();
361	                })
362	                .start();
363	        });
364	    }
365	
366	    /**
367	     * @ch 輕量落點演出：目標格高亮 + scale 彈一下，演出完成才 resolve（BC-7）
368	     * 預留接口：未來可在此依 type 改播專屬 Spine 演出
369	     */
370	    private PlayLandAnnounce(landIndex: number): Promise<void> {
371	        return new Promise<void>((resolve) => {
372	            const node = this.m_segmentNodes[landIndex];
373	            if (!node || !node.isValid) {
374	                resolve();
375	                return;
376	            }
377	            const s = FeatureWheelManager.ANNOUNCE_SCALE;
378	            const t = FeatureWheelManager.ANNOUNCE_TIME;
379	            tween(node)
380	                .to(t, { scale: v3(s, s, s) }, { easing: 'backOut' })
381	                .to(t, { scale: v3(1, 1, 1) }, { easing: 'backIn' })
382	                .call(() => resolve())
383	                .start();
384	        });
385	    }
386	
387	    /**
388	     * @ch 顯示/隱藏 UI（IF-4）
389	     */
390	    private SetUIShow(isShow: boolean) {
391	        if (this.m_rootNode) {
392	            this.m_rootNode.active = isShow;
393	        }
394	        // Idle：顯示時開始緩轉、隱藏時停止（PlaySpin 後不自動恢復，須由 RESUME_IDLE 手動恢復）
395	        this.m_isIdle = isShow;
396	    }
397	
398	    /**
399	     * @ch 手動恢復 Idle 緩轉（IF）
400	     * 用途：PlaySpin 後輪盤停住，呼叫端在盤面其他表演結束後觸發此方法才續轉
401	     * 注意：若仍在轉動中，由 update 的 m_isSpinning 守衛延後至轉完才實際緩轉
402	     */
403	    private ResumeIdle() {
404	        this.m_isIdle = true;
405	    }
406	
407	    /**
408	     * @ch dev-only 設定斷言（DR-3/DR-12 緩解：驗節點數量，順序語意仍須人工核對 prefab）
409	     */
410	    private DevAssertConfig() {
411	        if (!DEV) {
412	            return;
413	        }
414	        if (this.m_segmentSpriteChanges.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
415	            warn(`FeatureWheel 設定異常：SpriteChange 數 ${this.m_segmentSpriteChanges.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
416	        }
417	        if (this.m_segmentNodes.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
418	            warn(`FeatureWheel 設定異常：落點節點數 ${this.m_segmentNodes.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
419	        }
420	    }
421	    //#endregion 方法
422	
423	    //#region 測試功能
424	    /**@ch 測試用：當前轉動落點索引（每次轉動 +1 循環 0~11）*/
425	    private m_testLandIndex = 0;
426	    /**@ch 測試用：當前 UI 顯示狀態（給 DIGIT_4 切換）*/
427	    private m_testUIShown = false;
428	
429	    /**
430	     * @ch 註冊測試按鍵（僅 DEBUG 構建生效；正式構建零副作用）
431	     */
432	    private RegisterTestKeyCodes() {
433	        if (!DEBUG) {
434	            return;
435	        }
436	        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
437	    }
438	
439	    /**
440	     * @ch 取消註冊測試按鍵（與 RegisterTestKeyCodes 對稱，避免監聽洩漏）
441	     */
442	    private UnregisterTestKeyCodes() {
443	        if (!DEBUG) {
444	            return;
445	        }
446	        input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
447	    }
448	
449	    /**
450	     * @ch 檢查測試按鍵，走真實 eventManager 事件路徑驗證 FeatureWheel 功能
451	     * DIGIT_1：初始化 + 設定預設輪盤資料 + 顯示 UI（一鍵就緒）
452	     * DIGIT_2：轉動到下一格（循環 0~11）並印出落點結果（驗證旋轉/落點演出/callback）
453	     * DIGIT_3：重設隨機輪盤資料（驗證 icon 與乘倍數值動態更新）
454	     * DIGIT_4：切換顯示/隱藏 UI
455	     */
456	    private CheckTestKeyCode(event: EventKeyboard) {
457	        switch (event.keyCode) {
458	            case KeyCode.DIGIT_1:
459	                log('[FeatureWheel 測試] 初始化 + 設定預設資料 + 顯示 UI');
460	                // INIT 僅需非 null 物件以通過參數驗證並翻起 m_isInit；
461	                // m_gameView 在本元件未被讀取，測試以 this.node 佔位即可
462	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.INIT, this.node);
463	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, GetDefaultSegments());
464	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.SHOW_UI);
465	                break;
466	
467	            case KeyCode.DIGIT_2: {
468	                const landIndex = this.m_testLandIndex % FEATURE_WHEEL_SEGMENT_COUNT;
469	                this.m_testLandIndex++;
470	                log(`[FeatureWheel 測試] 轉動到第 ${landIndex} 格`);
471	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.PLAY_SPIN, landIndex, (result: SpinResult) => {
472	                    const valueText = result.value === undefined ? '-' : result.value;
473	                    log(`[FeatureWheel 測試] 落點結果 index=${result.index} type=${result.type} value=${valueText}`);
474	                });
475	                break;
476	            }
477	
478	            case KeyCode.DIGIT_3:
479	                log('[FeatureWheel 測試] 重設隨機輪盤資料');
480	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, this.BuildRandomTestSegments());
481	                break;
482	
483	            case KeyCode.DIGIT_4:
484	                this.m_testUIShown = !this.m_testUIShown;
485	                log(`[FeatureWheel 測試] 切換 UI 顯示 → ${this.m_testUIShown}`);
486	                eventManager.Dispatch(this.m_testUIShown ? FEATURE_WHEEL_EVENT.SHOW_UI : FEATURE_WHEEL_EVENT.HIDE_UI);
487	                break;
488	        }
489	    }
490	
491	    /**
492	     * @ch 產生 12 格隨機測試資料（type 隨機；Multiplier 帶隨機倍數）
493	     */
494	    private BuildRandomTestSegments(): SegmentDescriptor[] {
495	        const types = [
496	            FeatureWheelSegmentType.SymbolConvert,
497	            FeatureWheelSegmentType.Multiplier,
498	            FeatureWheelSegmentType.Upgrade,
499	            FeatureWheelSegmentType.GrandJP,
500	            FeatureWheelSegmentType.FreeGame,
501	        ];
502	        const multiplierValues = [2, 3, 5, 10, 20];
503	        const segments: SegmentDescriptor[] = [];
504	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
505	            const type = types[Math.floor(Math.random() * types.length)];
506	            const seg: SegmentDescriptor = { type };
507	            if (type === FeatureWheelSegmentType.Multiplier) {
508	                seg.value = multiplierValues[Math.floor(Math.random() * multiplierValues.length)];
509	            }
510	            segments.push(seg);
511	        }
512	        return segments;
513	    }
514	    //#endregion 測試功能
515	}
516

