1	import { _decorator, Component, Node, tween, Tween, TweenEasing } from 'cc';
2	import { Delegate } from './ExtraType';
3	
4	const { ccclass, property } = _decorator;
5	
6	/**
7	 * Cocos 版本的轉盤旋轉元件
8	 * - 以轉盤上方為中獎位置
9	 * - 提供：依索引停輪、跨區塊事件、完成回呼、可調整圈數/時間/方向/排序方向/獎項數
10	 */
11	@ccclass('RouletteRotate')
12	export class RouletteRotate extends Component {
13	
14	    //#region Events
15	    /** @ch 跨過每個 Item（格）時會觸發（可用於播放音效） */
16	    public CrossItemDelegate: Delegate = new Delegate();
17	    //#endregion
18	
19	    //#region Properties
20	    /** @ch 要旋轉的節點（轉盤根節點） */
21	    @property({ type: Node })
22	    public m_RotateRootNode: Node = null;
23	
24	    /** @ch 旋轉方向（順時針 / 逆時針） */
25	    @property({ tooltip: '順時針: 0, 逆時針: 1' })
26	    public m_RotateClockRotation: ClockRotation = ClockRotation.Clockwise;
27	
28	    /** @ch 盤面項目排序方向（影響角度計算） */
29	    @property({ tooltip: '順時針: 0, 逆時針: 1' })
30	    public m_ItemSortRotation: ClockRotation = ClockRotation.Clockwise;
31	
32	    /** @ch 總旋轉時間（秒） */
33	    @property({ tooltip: '總旋轉時間（秒）' })
34	    public m_fRotateTime: number = 5.0;
35	
36	    /** @ch 時間內額外旋轉的圈數（演出圈數） */
37	    @property({ tooltip: '時間內額外旋轉的圈數（演出圈數）' })
38	    public m_iCircleCount: number = 4;
39	
40	    /** @ch 獎項總數 */
41	    @property({ tooltip: '獎項總數' })
42	    public m_iItemCount: number = 9;
43	
44	    /** @ch easing 名稱（使用 Cocos tween easing 字串，如 'quadOut', 'cubicOut', 'sineInOut' 等） */
45	    @property({ tooltip: 'easing 名稱（使用 Cocos tween easing 字串，如 \'quadOut\', \'cubicOut\', \'sineInOut\' 等）' })
46	    public m_easing: TweenEasing = 'cubicOut';
47	
48	    /** @ch 停輪效果：是否啟用「過頭回彈/微補」 */
49	    @property({ tooltip: '停輪效果：是否啟用「過頭回彈/微補」' })
50	    public m_enableStopEffect: boolean = true;
51	
52	    /** @ch 停輪效果：過頭回彈機率（0~1）。例：0.6 表示 60% 走過頭回彈 */
53	    @property({ tooltip: '停輪效果：過頭回彈機率（0~1）。例：0.6 表示 60% 走過頭回彈' })
54	    public m_overshootChance: number = 0.6;
55	
56	    /** @ch 停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25） */
57	    @property({ tooltip: '停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25）' })
58	    public m_overshootMinRatio: number = 0.12;
59	
60	    /** @ch 停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25） */
61	    @property({ tooltip: '停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25）' })
62	    public m_overshootMaxRatio: number = 0.22;
63	
64	    /** @ch 停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10） */
65	    @property({ tooltip: '停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10）' })
66	    public m_microAdjustMinRatio: number = 0.03;
67	
68	    /** @ch 停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10） */
69	    @property({ tooltip: '停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10）' })
70	    public m_microAdjustMaxRatio: number = 0.08;
71	
72	    /** @ch 停輪效果：收尾時間（秒）。總時間會維持 m_fRotateTime，主旋轉時間 = m_fRotateTime - m_settleTime */
