193	    /**
194	     * @ch 根據參數計算目標角度（度）
195	     * - 以「上方」為中獎位置
196	     * @param stopIndex 要對準上方的位置索引
197	     * @returns 目標角度（度）
198	     */
199	    private CalcTargetAngle(stopIndex: number): number {
200	        if (this.m_iItemCount <= 0) {
201	            console.warn('[RouletteRotate] m_iItemCount 必須 > 0');
202	            return 0;
203	        }
204	
205	        // 每個 Item 的角度間距（保留兩位小數）
206	        const angleGap = Math.round((360 / this.m_iItemCount) * 100) / 100;
207	
208	        // 旋轉方向修正值：順時針 -1、逆時針 +1
209	        const rotateDirectionValue = (this.m_RotateClockRotation === ClockRotation.Clockwise) ? -1 : 1;
210	
211	        // 算出目標角度（以 0 度為基準）
212	        let targetAngle = 0;
213	        if (rotateDirectionValue === -1) {
214	            targetAngle = (360 - (stopIndex * angleGap) % 360);
215	        } else {
216	            targetAngle = (stopIndex * angleGap) % 360;
217	        }
218	
219	        // 若盤面排序為逆時鐘，需要鏡像
220	        if (this.m_ItemSortRotation === ClockRotation.Counterclockwise) {
221	            targetAngle = 360 - targetAngle;
222	        }
223	
224	        // 增加演出圈數
225	        targetAngle += this.m_iCircleCount * 360;
226	
227	        // 套用旋轉方向
228	        targetAngle *= rotateDirectionValue;
229	
230	        return targetAngle;
231	    }
