233	    /**
234	     * @ch 建立旋轉 tween（不自動 start）
235	     * @param targetAngle 目標角度（度）
236	     * @returns 旋轉 tween
237	     */
238	    private RotateRoulette(targetAngle: number): Tween<{ progress: number }> | null {
239	        const rotateNode = this.m_RotateRootNode;
240	        if (!rotateNode || !rotateNode.isValid) {
241	            return null;
242	        }
243	
244	        if (this.m_iItemCount <= 0) {
245	            console.warn('[RouletteRotate] m_iItemCount 必須 > 0');
246	            return null;
247	        }
248	
249	        // 目前 Z 角（0~360 取餘）
250	        const currentEuler = rotateNode.eulerAngles;
251	        const startAngle = ((currentEuler?.z || 0) % 360 + 360) % 360;
252	
253	        // 每格的角度間距
254	        const angleGap = Math.round((360 / this.m_iItemCount) * 100) / 100;
255	
256	        // 依 Unity 版邏輯：以進度(0~1)控制角度偏移
257	        let crossAngleGapTimes = -1;            // 已通知的跨越次數（初始 -1 確保第一格也觸發）
258	        let currentCrossAngleGapTimes = -1;     // 當前應該的跨越次數
259	
260	        // 停輪效果：主旋轉目標（可能包含過頭/微補）
261	        const rotateDirectionSign = (this.m_RotateClockRotation === ClockRotation.Clockwise) ? -1 : 1;
262	        const clamp01 = (v: number) => Math.max(0, Math.min(1, v));
263	        const clamp = (v: number, min: number, max: number) => Math.max(min, Math.min(max, v));
264	        const randRange = (min: number, max: number) => min + Math.random() * (max - min);
265	
266	        const enableStopEffect = this.m_enableStopEffect && this.m_iItemCount > 0;
267	        const overshootChance = clamp01(this.m_overshootChance);
268	
269	        const overshootRatio = clamp(
270	            randRange(this.m_overshootMinRatio, this.m_overshootMaxRatio),
271	            0,
272	            0.24
273	        );
274	        const microRatio = clamp(
275	            randRange(this.m_microAdjustMinRatio, this.m_microAdjustMaxRatio),
276	            0,
277	            0.10
278	        );
279	
280	        const overshootDeg = angleGap * overshootRatio;
281	        const microDeg = angleGap * microRatio;
282	
283	        const roll = Math.random();
284	        const useOvershoot = enableStopEffect && (roll < overshootChance);
285	        const mainTargetAngle = enableStopEffect
286	            ? (useOvershoot
287	                ? (targetAngle + rotateDirectionSign * overshootDeg) // 過頭：沿旋轉方向多一點點
288	                : (targetAngle - rotateDirectionSign * microDeg))    // 微補：沿旋轉方向少一點點
289	            : targetAngle;
290	
291	        // 目標偏移角度：將 rotation 從當前角度推進 mainTargetAngle
292	        const mainFixTargetAngle = mainTargetAngle - startAngle;
293	        const mainEndAngle = startAngle + mainFixTargetAngle;
294	        const settleFixTargetAngle = targetAngle - mainEndAngle;
295	
296	        // 總時間維持 m_fRotateTime：主旋轉時間 = m_fRotateTime - m_settleTime
297	        const settleTime = enableStopEffect ? Math.max(0, this.m_settleTime) : 0;
298	        const mainRotateTime = Math.max(0.01, this.m_fRotateTime - settleTime);
299	
300	        if (this.m_logStopEffectPick) {
301	            const effectName = enableStopEffect ? (useOvershoot ? '過頭回彈' : '微補') : '關閉(直接停)';
302	            const effectDeg = enableStopEffect ? (useOvershoot ? overshootDeg : microDeg) : 0;
303	            console.log(
304	                `[RouletteRotate] StopEffect=${effectName}` +
305	                ` | roll=${roll.toFixed(3)} chance=${overshootChance.toFixed(2)}` +
306	                ` | itemCount=${this.m_iItemCount} angleGap=${angleGap.toFixed(2)}` +
307	                ` | effectDeg=${effectDeg.toFixed(2)} dir=${rotateDirectionSign}` +
308	                ` | mainTime=${mainRotateTime.toFixed(2)} settleTime=${settleTime.toFixed(2)}`
309	            );
310	        }
311	
312	        const animTarget = { progress: 0 };
313	        const tw = tween(animTarget)
314	            .to(mainRotateTime, { progress: 1 }, {
315	                easing: this.m_easing,
316	                onUpdate: (t: any, ratio?: number) => {
317	                    const angleOffset = mainFixTargetAngle * t.progress;
318	                    const updateZ = angleOffset + startAngle;
319	
320	                    // 實際套用角度
321	                    rotateNode.setRotationFromEuler(0, 0, updateZ);
322	
323	                    // 跨過一格就通知一次
324	                    currentCrossAngleGapTimes = Math.floor(angleOffset / angleGap);
325	                    if (crossAngleGapTimes !== currentCrossAngleGapTimes) {
326	                        crossAngleGapTimes = currentCrossAngleGapTimes;
327	                        if (this.CrossItemDelegate) {
328	                            this.CrossItemDelegate.notify();
329	                        }
330	                    }
331	                }
332	            })
333	            .set({ progress: 0 })
334	            .to(settleTime, { progress: 1 }, {
335	                easing: this.m_settleEasing,
336	                onUpdate: (t: any) => {
337	                    // 收尾段：回彈/微補（預設不再觸發跨格通知，避免回彈反向 tick）
338	                    const angleOffset = settleFixTargetAngle * t.progress;
339	                    const updateZ = mainEndAngle + angleOffset;
340	                    rotateNode.setRotationFromEuler(0, 0, updateZ);
341	
342	                    if (!this.m_disableCrossItemDuringSettle) {
343	                        // 若需要收尾也打 tick，使用「相對主旋轉起點」的累積 offset
344	                        const totalOffset = mainFixTargetAngle + angleOffset;
345	                        currentCrossAngleGapTimes = Math.floor(totalOffset / angleGap);
346	                        if (crossAngleGapTimes !== currentCrossAngleGapTimes) {
347	                            crossAngleGapTimes = currentCrossAngleGapTimes;
348	                            if (this.CrossItemDelegate) {
349	                                this.CrossItemDelegate.notify();
350	                            }
351	                        }
352	                    }
353	                }
354	            })
355	            .call(() => {
356	                // 最終校正一次角度（正規化到 0~360）
357	                const finalZ = targetAngle;
358	                const normalizedZ = ((finalZ % 360) + 360) % 360;
359	                rotateNode.setRotationFromEuler(0, 0, normalizedZ);
360	
361	                this.m_currentTween = null;
362	                const cb = this.m_finishCallback;
363	                this.m_finishCallback = null;
364	                if (cb) { cb(); }
365	            });
366	
367	        return tw as Tween<{ progress: number }>;
368	    }
369	    //#endregion Private Helpers
370	}
371	
372	export enum ClockRotation {
373	    /** 順時針 */
374	    Clockwise = 0,
375	    /** 逆時針 */
376	    Counterclockwise = 1,
377	}
