import { _decorator, Component, Node, tween, Tween, TweenEasing } from 'cc';
import { Delegate } from './ExtraType';

const { ccclass, property } = _decorator;

/**
 * Cocos 版本的轉盤旋轉元件
 * - 以轉盤上方為中獎位置
 * - 提供：依索引停輪、跨區塊事件、完成回呼、可調整圈數/時間/方向/排序方向/獎項數
 */
@ccclass('RouletteRotate')
export class RouletteRotate extends Component {

    //#region Events
    /** @ch 跨過每個 Item（格）時會觸發（可用於播放音效） */
    public CrossItemDelegate: Delegate = new Delegate();
    //#endregion

    //#region Properties
    /** @ch 要旋轉的節點（轉盤根節點） */
    @property({ type: Node })
    public m_RotateRootNode: Node = null;

    /** @ch 旋轉方向（順時針 / 逆時針） */
    @property({ tooltip: '順時針: 0, 逆時針: 1' })
    public m_RotateClockRotation: ClockRotation = ClockRotation.Clockwise;

    /** @ch 盤面項目排序方向（影響角度計算） */
    @property({ tooltip: '順時針: 0, 逆時針: 1' })
    public m_ItemSortRotation: ClockRotation = ClockRotation.Clockwise;

    /** @ch 總旋轉時間（秒） */
    @property({ tooltip: '總旋轉時間（秒）' })
    public m_fRotateTime: number = 5.0;

    /** @ch 時間內額外旋轉的圈數（演出圈數） */
    @property({ tooltip: '時間內額外旋轉的圈數（演出圈數）' })
    public m_iCircleCount: number = 4;

    /** @ch 獎項總數 */
    @property({ tooltip: '獎項總數' })
    public m_iItemCount: number = 9;

    /** @ch easing 名稱（使用 Cocos tween easing 字串，如 'quadOut', 'cubicOut', 'sineInOut' 等） */
    @property({ tooltip: 'easing 名稱（使用 Cocos tween easing 字串，如 \'quadOut\', \'cubicOut\', \'sineInOut\' 等）' })
    public m_easing: TweenEasing = 'cubicOut';

    /** @ch 停輪效果：是否啟用「過頭回彈/微補」 */
    @property({ tooltip: '停輪效果：是否啟用「過頭回彈/微補」' })
    public m_enableStopEffect: boolean = true;

    /** @ch 停輪效果：過頭回彈機率（0~1）。例：0.6 表示 60% 走過頭回彈 */
    @property({ tooltip: '停輪效果：過頭回彈機率（0~1）。例：0.6 表示 60% 走過頭回彈' })
    public m_overshootChance: number = 0.6;

    /** @ch 停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25） */
    @property({ tooltip: '停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25）' })
    public m_overshootMinRatio: number = 0.12;

    /** @ch 停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25） */
    @property({ tooltip: '停輪效果：過頭回彈幅度（以單格角度比例計算，建議 < 0.25）' })
    public m_overshootMaxRatio: number = 0.22;

    /** @ch 停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10） */
    @property({ tooltip: '停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10）' })
    public m_microAdjustMinRatio: number = 0.03;

    /** @ch 停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10） */
    @property({ tooltip: '停輪效果：微補幅度（以單格角度比例計算，建議 < 0.10）' })
    public m_microAdjustMaxRatio: number = 0.08;

    /** @ch 停輪效果：收尾時間（秒）。總時間會維持 m_fRotateTime，主旋轉時間 = m_fRotateTime - m_settleTime */
    @property({ tooltip: '停輪效果：收尾時間（秒）。總時間會維持 m_fRotateTime，主旋轉時間 = m_fRotateTime - m_settleTime' })
    public m_settleTime: number = 0.25;

    /** @ch 停輪效果：收尾 easing（回彈/微補段使用） */
    @property({ tooltip: '停輪效果：收尾 easing（回彈/微補段使用）' })
    public m_settleEasing: TweenEasing = 'sineOut';

    /** @ch 停輪效果：收尾段是否停止跨格通知（避免回彈/微補造成 tick 反向） */
    @property({ tooltip: '停輪效果：收尾段是否停止跨格通知（避免回彈/微補造成 tick 反向）' })
    public m_disableCrossItemDuringSettle: boolean = true;

    /** @ch 停輪效果：是否印出本次停輪選擇（過頭回彈/微補）供除錯確認 */
    @property({ tooltip: '停輪效果：是否印出本次停輪選擇（過頭回彈/微補）供除錯確認' })
    public m_logStopEffectPick: boolean = false;

    /** @ch 內部：目前的旋轉 tween */
    private m_currentTween: Tween<{ progress: number }> | null = null;

    /** @ch 內部：本次旋轉的完成回呼 */
    private m_finishCallback: (() => void) | null = null;
    //#endregion

    //#region UnityLifeCycle
    protected onDestroy(): void {
        // 停止旋轉並觸發回呼（讓外部邏輯知道組件已銷毀）
        this.Stop(true);

        // 清理 Delegate
        if (this.CrossItemDelegate) {
            this.CrossItemDelegate.clear();
            this.CrossItemDelegate = null;
        }

        // 清理引用
        this.m_RotateRootNode = null;
        this.m_finishCallback = null;
    }
    //#endregion

    //#region Public API
    /**
     * @ch 依角度重置轉盤 Z 軸角度（度數）
     * @param angleDeg 角度（度數）
     */
    public ResetRouletteAngle(angleDeg: number = 0): void {
        if (!this.m_RotateRootNode || !this.m_RotateRootNode.isValid) {
            return;
        }
        this.m_RotateRootNode.setRotationFromEuler(0, 0, angleDeg);
    }

    /**
     * @ch 依索引重置轉盤角度
     * @param stopIndex 要對準上方的位置索引
     */
    public ResetRouletteAngleByIndex(stopIndex: number): void {
        const target = this.CalcTargetAngle(stopIndex);
        this.ResetRouletteAngle(target);
    }

    /**
     * @ch 開始旋轉到指定索引
     * @param stopIndex 停到的目標索引
     * @param finishCallback 完成回呼（可選）
     */
    public StartRotate(stopIndex: number, finishCallback?: () => void): void {
        this.m_finishCallback = finishCallback || null;

        if (!this.m_RotateRootNode || !this.m_RotateRootNode.isValid) {
            if (this.m_finishCallback) { this.m_finishCallback(); }
            return;
        }

        // 停止上一個旋轉
        this.Stop();

        const targetAngle = this.CalcTargetAngle(stopIndex);
        this.m_currentTween = this.RotateRoulette(targetAngle);
        if (this.m_currentTween) {
            this.m_currentTween.start();
        }
    }

    /** @ch 是否正在旋轉 */
    public IsRotating(): boolean {
        return this.m_currentTween !== null;
    }

    /**
     * @ch 停止旋轉
     * @param triggerCallback 是否觸發完成回呼（預設 false）
     */
    public Stop(triggerCallback: boolean = false): void {
        if (this.m_currentTween) {
            this.m_currentTween.stop();
            this.m_currentTween = null;

            // 若需要觸發回呼
            if (triggerCallback && this.m_finishCallback) {
                const cb = this.m_finishCallback;
                this.m_finishCallback = null;
                cb();
            } else {
                this.m_finishCallback = null;
            }
        }
    }

    /**
     * @ch 設定轉盤根節點是否顯示
     * @param isActive 是否顯示
     */
    public SetRotateRootNodeShow(isShow: boolean): void {
        if (this.m_RotateRootNode) {
            this.m_RotateRootNode.active = isShow;
        }
    }
    //#endregion Public API

    //#region Private Helpers
    /**
     * @ch 根據參數計算目標角度（度）
     * - 以「上方」為中獎位置
     * @param stopIndex 要對準上方的位置索引
     * @returns 目標角度（度）
     */
    private CalcTargetAngle(stopIndex: number): number {
        if (this.m_iItemCount <= 0) {
            console.warn('[RouletteRotate] m_iItemCount 必須 > 0');
            return 0;
        }

        // 每個 Item 的角度間距（保留兩位小數）
        const angleGap = Math.round((360 / this.m_iItemCount) * 100) / 100;

        // 旋轉方向修正值：順時針 -1、逆時針 +1
        const rotateDirectionValue = (this.m_RotateClockRotation === ClockRotation.Clockwise) ? -1 : 1;

        // 算出目標角度（以 0 度為基準）
        let targetAngle = 0;
        if (rotateDirectionValue === -1) {
            targetAngle = (360 - (stopIndex * angleGap) % 360);
        } else {
            targetAngle = (stopIndex * angleGap) % 360;
        }

        // 若盤面排序為逆時鐘，需要鏡像
        if (this.m_ItemSortRotation === ClockRotation.Counterclockwise) {
            targetAngle = 360 - targetAngle;
        }

        // 增加演出圈數
        targetAngle += this.m_iCircleCount * 360;

        // 套用旋轉方向
        targetAngle *= rotateDirectionValue;

        return targetAngle;
    }

    /**
     * @ch 建立旋轉 tween（不自動 start）
     * @param targetAngle 目標角度（度）
     * @returns 旋轉 tween
     */
    private RotateRoulette(targetAngle: number): Tween<{ progress: number }> | null {
        const rotateNode = this.m_RotateRootNode;
        if (!rotateNode || !rotateNode.isValid) {
            return null;
        }

        if (this.m_iItemCount <= 0) {
            console.warn('[RouletteRotate] m_iItemCount 必須 > 0');
            return null;
        }

        // 目前 Z 角（0~360 取餘）
        const currentEuler = rotateNode.eulerAngles;
        const startAngle = ((currentEuler?.z || 0) % 360 + 360) % 360;

        // 每格的角度間距
        const angleGap = Math.round((360 / this.m_iItemCount) * 100) / 100;

        // 依 Unity 版邏輯：以進度(0~1)控制角度偏移
        let crossAngleGapTimes = -1;            // 已通知的跨越次數（初始 -1 確保第一格也觸發）
        let currentCrossAngleGapTimes = -1;     // 當前應該的跨越次數

        // 停輪效果：主旋轉目標（可能包含過頭/微補）
        const rotateDirectionSign = (this.m_RotateClockRotation === ClockRotation.Clockwise) ? -1 : 1;
        const clamp01 = (v: number) => Math.max(0, Math.min(1, v));
        const clamp = (v: number, min: number, max: number) => Math.max(min, Math.min(max, v));
        const randRange = (min: number, max: number) => min + Math.random() * (max - min);

        const enableStopEffect = this.m_enableStopEffect && this.m_iItemCount > 0;
        const overshootChance = clamp01(this.m_overshootChance);

        const overshootRatio = clamp(
            randRange(this.m_overshootMinRatio, this.m_overshootMaxRatio),
            0,
            0.24
        );
        const microRatio = clamp(
            randRange(this.m_microAdjustMinRatio, this.m_microAdjustMaxRatio),
            0,
            0.10
        );

        const overshootDeg = angleGap * overshootRatio;
        const microDeg = angleGap * microRatio;

        const roll = Math.random();
        const useOvershoot = enableStopEffect && (roll < overshootChance);
        const mainTargetAngle = enableStopEffect
            ? (useOvershoot
                ? (targetAngle + rotateDirectionSign * overshootDeg) // 過頭：沿旋轉方向多一點點
                : (targetAngle - rotateDirectionSign * microDeg))    // 微補：沿旋轉方向少一點點
            : targetAngle;

        // 目標偏移角度：將 rotation 從當前角度推進 mainTargetAngle
        const mainFixTargetAngle = mainTargetAngle - startAngle;
        const mainEndAngle = startAngle + mainFixTargetAngle;
        const settleFixTargetAngle = targetAngle - mainEndAngle;

        // 總時間維持 m_fRotateTime：主旋轉時間 = m_fRotateTime - m_settleTime
        const settleTime = enableStopEffect ? Math.max(0, this.m_settleTime) : 0;
        const mainRotateTime = Math.max(0.01, this.m_fRotateTime - settleTime);

        if (this.m_logStopEffectPick) {
            const effectName = enableStopEffect ? (useOvershoot ? '過頭回彈' : '微補') : '關閉(直接停)';
            const effectDeg = enableStopEffect ? (useOvershoot ? overshootDeg : microDeg) : 0;
            console.log(
                `[RouletteRotate] StopEffect=${effectName}` +
                ` | roll=${roll.toFixed(3)} chance=${overshootChance.toFixed(2)}` +
                ` | itemCount=${this.m_iItemCount} angleGap=${angleGap.toFixed(2)}` +
                ` | effectDeg=${effectDeg.toFixed(2)} dir=${rotateDirectionSign}` +
                ` | mainTime=${mainRotateTime.toFixed(2)} settleTime=${settleTime.toFixed(2)}`
            );
        }

        const animTarget = { progress: 0 };
        const tw = tween(animTarget)
            .to(mainRotateTime, { progress: 1 }, {
                easing: this.m_easing,
                onUpdate: (t: any, ratio?: number) => {
                    const angleOffset = mainFixTargetAngle * t.progress;
                    const updateZ = angleOffset + startAngle;

                    // 實際套用角度
                    rotateNode.setRotationFromEuler(0, 0, updateZ);

                    // 跨過一格就通知一次
                    currentCrossAngleGapTimes = Math.floor(angleOffset / angleGap);
                    if (crossAngleGapTimes !== currentCrossAngleGapTimes) {
                        crossAngleGapTimes = currentCrossAngleGapTimes;
                        if (this.CrossItemDelegate) {
                            this.CrossItemDelegate.notify();
                        }
                    }
                }
            })
            .set({ progress: 0 })
            .to(settleTime, { progress: 1 }, {
                easing: this.m_settleEasing,
                onUpdate: (t: any) => {
                    // 收尾段：回彈/微補（預設不再觸發跨格通知，避免回彈反向 tick）
                    const angleOffset = settleFixTargetAngle * t.progress;
                    const updateZ = mainEndAngle + angleOffset;
                    rotateNode.setRotationFromEuler(0, 0, updateZ);

                    if (!this.m_disableCrossItemDuringSettle) {
                        // 若需要收尾也打 tick，使用「相對主旋轉起點」的累積 offset
                        const totalOffset = mainFixTargetAngle + angleOffset;
                        currentCrossAngleGapTimes = Math.floor(totalOffset / angleGap);
                        if (crossAngleGapTimes !== currentCrossAngleGapTimes) {
                            crossAngleGapTimes = currentCrossAngleGapTimes;
                            if (this.CrossItemDelegate) {
                                this.CrossItemDelegate.notify();
                            }
                        }
                    }
                }
            })
            .call(() => {
                // 最終校正一次角度（正規化到 0~360）
                const finalZ = targetAngle;
                const normalizedZ = ((finalZ % 360) + 360) % 360;
                rotateNode.setRotationFromEuler(0, 0, normalizedZ);

                this.m_currentTween = null;
                const cb = this.m_finishCallback;
                this.m_finishCallback = null;
                if (cb) { cb(); }
            });

        return tw as Tween<{ progress: number }>;
    }
    //#endregion Private Helpers
}

export enum ClockRotation {
    /** 順時針 */
    Clockwise = 0,
    /** 逆時針 */
    Counterclockwise = 1,
}

