import { _decorator, Component } from 'cc';

const { ccclass, property } = _decorator;

/**
 * @ch 持續旋轉元件（通用 · self-contained）
 * 單一職責：掛上後讓所屬節點繞 Z 軸永遠自轉，與任何業務邏輯零耦合。
 * - 適用：魔法字環、裝飾光環等需要「不斷旋轉」的節點
 * - 控制：以 component 的 enabled 開關（enabled=false 即停，built-in，不另設 API）
 * - 不負責：落點/停輪/tween 演出（那是 RouletteRotate 的職責）
 */
@ccclass('ContinuousRotate')
export class ContinuousRotate extends Component {
    //#region 屬性
    /**@ch 一圈秒數（越大越慢；≤0 視為不轉）*/
    @property({ displayName: '一圈秒數' })
    private m_secondsPerRev: number = 60;

    /**@ch 轉動方向：勾選=順時針，取消=逆時針（順時針 = z 遞減，與專案其他輪盤一致）*/
    @property({ displayName: '順時針轉動' })
    private m_clockwise: boolean = true;
    //#endregion 屬性

    //#region 生命週期
    update(dt: number) {
        if (this.m_secondsPerRev <= 0) {
            return;
        }
        const dir = this.m_clockwise ? -1 : 1;
        const deltaAngle = dir * (360 / this.m_secondsPerRev) * dt;
        // 正規化防連續累積漂移（與 FeatureWheel/RouletteRotate 收尾一致）
        const next = this.NormalizeAngle(this.node.eulerAngles.z + deltaAngle);
        this.node.setRotationFromEuler(0, 0, next);
    }
    //#endregion 生命週期

    //#region 方法
    /**
     * @ch 將角度正規化到 [0, 360)
     */
    private NormalizeAngle(angle: number): number {
        return ((angle % 360) + 360) % 360;
    }
    //#endregion 方法
}

