 * - 適用：魔法字環、裝飾光環等需要「不斷旋轉」的節點
 * - 控制：可在 Inspector 設初值；執行期用公開 API（Pause/Resume/SetSecondsPerRev/SetClockwise）動態調整
 * - 不負責：落點/停輪/tween 演出（那是 RouletteRotate 的職責）
 */
@ccclass('ContinuousRotate')
export class ContinuousRotate extends Component {
    //#region 屬性
    /**@ch 一圈秒數（越大越慢；≤0 視為不轉）*/
    @property({ displayName: '一圈秒數' })
    private m_secondsPerRev: number = 60;

    /**@ch 轉動方向：勾選=順時針，取消=逆時針（順時針 = z 遞減，與專案其他輪盤一致）*/
    @property({ displayName: '順時針轉動' })
    private m_clockwise: boolean = true;
    //#endregion 屬性

    //#region 變數
    /**@ch 是否暫停（暫停時保留當前角度，Resume 從原處續轉）*/
    private m_paused: boolean = false;
    //#endregion 變數

    //#region 生命週期
    update(dt: number) {
        if (this.m_paused || this.m_secondsPerRev <= 0) {
            return;
        }
        const dir = this.m_clockwise ? -1 : 1;
        const deltaAngle = dir * (360 / this.m_secondsPerRev) * dt;
        // 正規化防連續累積漂移（與 FeatureWheel/RouletteRotate 收尾一致）
        const next = this.NormalizeAngle(this.node.eulerAngles.z + deltaAngle);
        this.node.setRotationFromEuler(0, 0, next);
    }
    //#endregion 生命週期

    //#region 公開 API
    /**
     * @ch 暫停旋轉（保留當前角度，不重置）
     */
    public Pause(): void {
        this.m_paused = true;
    }

    /**
     * @ch 恢復旋轉（從當前角度續轉）
     */
    public Resume(): void {
        this.m_paused = false;
    }

    /**
     * @ch 是否正在旋轉（未暫停且速度有效）
     */
    public IsRotating(): boolean {
        return !this.m_paused && this.m_secondsPerRev > 0;
    }

    /**
     * @ch 設定轉速（一圈秒數；越大越慢，≤0 視為不轉）
     * 用途：動態變快/變慢，例：SetSecondsPerRev(30) 比預設 60 快一倍
     * @param seconds 一圈所需秒數
     */
    public SetSecondsPerRev(seconds: number): void {
        this.m_secondsPerRev = seconds;
    }

    /**
     * @ch 設定轉動方向
     * @param clockwise true=順時針，false=逆時針
     */
    public SetClockwise(clockwise: boolean): void {
        this.m_clockwise = clockwise;
    }
    //#endregion 公開 API

    //#region 方法
    /**
     * @ch 將角度正規化到 [0, 360)
     */
    private NormalizeAngle(angle: number): number {
        return ((angle % 360) + 360) % 360;
    }
    //#endregion 方法
}

